import React, { useState, useRef, useEffect } from 'react';
import { Send, Paperclip, Bot, User, Loader2 } from 'lucide-react';
import { Message } from '../../types';
import { generateResponse } from '../../services/geminiService';
import AnalysisPanel from './AnalysisPanel';

const ChatPanel: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'model',
      text: "Hello! I'm SML.AI, your sustainable material assistant. I can help you find eco-friendly materials, analyze their durability, or navigate ISO 14000 regulations. How can I help you today?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }));

        const responseText = await generateResponse(userMsg.text, history);

        const botMsg: Message = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            text: responseText,
            timestamp: new Date()
        };
        setMessages(prev => [...prev, botMsg]);
    } catch (e) {
        console.error(e);
    } finally {
        setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex h-full w-full">
        {/* Chat Area (2/3 width relative to this component's container in parent grid) */}
        <div className="flex-1 flex flex-col min-w-0 bg-white relative">
            <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        {msg.role === 'model' && (
                            <div className="w-8 h-8 rounded-full bg-sml-green-100 flex items-center justify-center text-sml-green-600 flex-shrink-0 mt-1">
                                <Bot size={18} />
                            </div>
                        )}
                        <div className={`max-w-[80%] rounded-2xl px-5 py-3.5 text-sm leading-relaxed ${
                            msg.role === 'user' 
                            ? 'bg-sml-slate-800 text-white rounded-tr-none' 
                            : 'bg-gray-100 text-gray-800 rounded-tl-none'
                        }`}>
                            {msg.text.split('\n').map((line, i) => (
                                <p key={i} className="min-h-[1em]">{line}</p>
                            ))}
                        </div>
                        {msg.role === 'user' && (
                            <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-gray-600 flex-shrink-0 mt-1">
                                <User size={18} />
                            </div>
                        )}
                    </div>
                ))}
                {loading && (
                    <div className="flex gap-4 justify-start">
                        <div className="w-8 h-8 rounded-full bg-sml-green-100 flex items-center justify-center text-sml-green-600 flex-shrink-0">
                            <Bot size={18} />
                        </div>
                        <div className="bg-gray-100 rounded-2xl rounded-tl-none px-5 py-3.5 flex items-center">
                            <Loader2 size={18} className="animate-spin text-gray-400" />
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white border-t border-gray-100 sticky bottom-0">
                <div className="max-w-4xl mx-auto relative flex items-end gap-2 bg-gray-50 border border-gray-200 rounded-2xl p-2 focus-within:ring-2 focus-within:ring-sml-green-100 focus-within:border-sml-green-300 transition-all shadow-sm">
                    <button className="p-2 text-gray-400 hover:text-gray-600 rounded-xl hover:bg-gray-200/50 transition-colors">
                        <Paperclip size={20} />
                    </button>
                    <textarea 
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder="Ask about sustainable materials..." 
                        className="flex-1 bg-transparent border-none focus:ring-0 resize-none max-h-32 py-2.5 text-sm text-gray-800 placeholder-gray-400 scrollbar-none"
                        rows={1}
                    />
                    <button 
                        onClick={handleSend}
                        disabled={!input.trim() || loading}
                        className="p-2 bg-sml-green-600 text-white rounded-xl hover:bg-sml-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-sm"
                    >
                        <Send size={18} />
                    </button>
                </div>
                <p className="text-center text-xs text-gray-400 mt-2">
                    SML.AI can make mistakes. Please verify important information about ISO standards.
                </p>
            </div>
        </div>

        {/* Info/Analysis Panel (1/3 width) - Only visible on large screens */}
        <div className="w-80 lg:w-96 border-l border-gray-200 hidden md:block bg-white flex-shrink-0">
            <AnalysisPanel />
        </div>
    </div>
  );
};

export default ChatPanel;

