      newSet.delete(id);
    } else {
      if (newSet.size >= 5) {
          alert("最多同時比較 5 項材質");
          return;
      }
      newSet.add(id);
    }
    setSelectedIds(newSet);
  };

  const openDetail = (material: MaterialData) => {
    setActiveMaterial(material);
  };

  const handleExportSpecSheet = () => {
    alert("正在匯出材料規格比較表 (.csv)...");
