    type: 'Metal Alloy (6000 Series)',
    color: 0x9ca3af, // Grey
    roughness: 0.25,
    metalness: 0.9, // Metallic
    stats: { co2: '4.5 kg', recyclability: 'A', cost: '$', durability: 95 },
    description: '無限次循環再造的高強度鋁合金，表面經陽極處理，展現現代工業的冷冽美學。'
  }
];

const MaterialSimulation: React.FC = () => {
  const mountRef = useRef<HTMLDivElement>(null);
  const [selectedMat, setSelectedMat] = useState<SimulationMaterial>(MATERIALS[0]);

  // Refs to access Three.js objects inside interaction handlers
  const meshRefs = useRef<THREE.Mesh[]>([]);

  useEffect(() => {
    if (!mountRef.current) return;

    // --- 1. Scene Setup ---
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0xf8fafc); // Slate-50 equivalent
    // Add subtle fog for depth
    scene.fog = new THREE.Fog(0xf8fafc, 5, 20);

    const camera = new THREE.PerspectiveCamera(45, mountRef.current.clientWidth / mountRef.current.clientHeight, 0.1, 100);
    camera.position.set(0, 1.5, 6);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(mountRef.current.clientWidth, mountRef.current.clientHeight);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    mountRef.current.appendChild(renderer.domElement);

    // --- 2. Lighting ---
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffffff, 1);
    dirLight.position.set(5, 10, 7);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.width = 1024;
    dirLight.shadow.mapSize.height = 1024;
    scene.add(dirLight);

    const spotLight = new THREE.SpotLight(0x0ea5e9, 2); // Teal accent light
    spotLight.position.set(-5, 0, 5);
    scene.add(spotLight);

    // --- 3. Geometry (The Glasses) ---
    const glassesGroup = new THREE.Group();

    // Materials base
    const mainMaterial = new THREE.MeshPhysicalMaterial({
      color: selectedMat.color,
      roughness: selectedMat.roughness,
      metalness: selectedMat.metalness,
      transmission: selectedMat.transmission || 0,
      thickness: 1.0,
      clearcoat: 0.5,
    });

    // Frames (Toruses)
    const frameGeo = new THREE.TorusGeometry(0.8, 0.12, 16, 50);
    // Left
    const leftFrame = new THREE.Mesh(frameGeo, mainMaterial);
    leftFrame.position.set(-1, 0, 0);
    leftFrame.castShadow = true;
    glassesGroup.add(leftFrame);
    // Right
    const rightFrame = new THREE.Mesh(frameGeo, mainMaterial);
    rightFrame.position.set(1, 0, 0);
    rightFrame.castShadow = true;
    glassesGroup.add(rightFrame);

    // Bridge (Box)
    const bridgeGeo = new THREE.BoxGeometry(0.4, 0.08, 0.05);
    const bridge = new THREE.Mesh(bridgeGeo, mainMaterial);
    bridge.position.set(0, 0.1, 0);
    bridge.castShadow = true;
    glassesGroup.add(bridge);

    // Temples/Arms (Cylinders/Boxes)
    const armGeo = new THREE.BoxGeometry(0.1, 0.1, 3);
    // Left Arm
    const leftArm = new THREE.Mesh(armGeo, mainMaterial);
    leftArm.position.set(-1.8, 0.1, -1.5);
    leftArm.castShadow = true;
    glassesGroup.add(leftArm);
    // Right Arm
    const rightArm = new THREE.Mesh(armGeo, mainMaterial);
    rightArm.position.set(1.8, 0.1, -1.5);
    rightArm.castShadow = true;
    glassesGroup.add(rightArm);

    // Hinges (Small Cylinders) - Cosmetic
    const hingeGeo = new THREE.CylinderGeometry(0.1, 0.1, 0.2, 16);
    const hingeMat = new THREE.MeshStandardMaterial({ color: 0x333333, metalness: 0.8, roughness: 0.2 });
    const leftHinge = new THREE.Mesh(hingeGeo, hingeMat);
    leftHinge.rotation.z = Math.PI / 2;
    leftHinge.position.set(-1.8, 0.1, 0);
    glassesGroup.add(leftHinge);
    const rightHinge = new THREE.Mesh(hingeGeo, hingeMat);
    rightHinge.rotation.z = Math.PI / 2;
    rightHinge.position.set(1.8, 0.1, 0);
    glassesGroup.add(rightHinge);

    // Store references to update material later
    meshRefs.current = [leftFrame, rightFrame, bridge, leftArm, rightArm];

    scene.add(glassesGroup);

    // --- 4. Animation ---
    let animationId: number;
    const animate = () => {
      animationId = requestAnimationFrame(animate);

      // Idle Animation: Floating & Rotating
      const time = Date.now() * 0.001;
      glassesGroup.rotation.y = Math.sin(time * 0.5) * 0.15; // Gentle yaw
      glassesGroup.rotation.x = Math.sin(time * 0.3) * 0.05; // Gentle pitch
      glassesGroup.position.y = Math.sin(time * 1) * 0.1; // Bobbing

      renderer.render(scene, camera);
    };
    animate();

    // --- 5. Cleanup ---
    const handleResize = () => {
      if (!mountRef.current) return;
      camera.aspect = mountRef.current.clientWidth / mountRef.current.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(mountRef.current.clientWidth, mountRef.current.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(animationId);
      if (mountRef.current) {
        mountRef.current.removeChild(renderer.domElement);
      }
      // Dispose Geometries/Materials to prevent leaks
      frameGeo.dispose();
      bridgeGeo.dispose();
      armGeo.dispose();
      mainMaterial.dispose();
    };
  }, []); // Run once on mount

  // --- Update Material when State Changes ---
  useEffect(() => {
    meshRefs.current.forEach(mesh => {
      if (mesh.material instanceof THREE.MeshPhysicalMaterial) {
        mesh.material.color.setHex(selectedMat.color);
        mesh.material.roughness = selectedMat.roughness;
        mesh.material.metalness = selectedMat.metalness;
        mesh.material.transmission = selectedMat.transmission || 0;
        mesh.material.needsUpdate = true;
      }
    });
  }, [selectedMat]);


  return (
    <div className="flex h-full w-full bg-gray-50 relative overflow-hidden">

        {/* CENTER: 3D Canvas */}
        <div ref={mountRef} className="flex-1 h-full w-full cursor-grab active:cursor-grabbing outline-none" />

        {/* OVERLAY: Title */}
        <div className="absolute top-6 left-8 pointer-events-none">
            <h2 className="text-3xl font-bold text-gray-800 flex items-center gap-3">
                <Box className="text-sml-teal-600" />
                產品模擬實驗室
            </h2>
            <p className="text-gray-500 mt-1 max-w-md">
                即時預覽不同永續材質在產品上的視覺呈現，並獲取環境影響數據分析。
            </p>
        </div>

