    stats: { co2: '4.5 kg', recyclability: 'A', cost: '$', durability: 95 },
    description: '無限次循環再造的高強度鋁合金，表面經陽極處理，展現現代工業的冷冽美學。'
  }
];

const MaterialSimulation: React.FC = () => {
  const mountRef = useRef<HTMLDivElement>(null);
  const [selectedMat, setSelectedMat] = useState<SimulationMaterial>(MATERIALS[0]);
  const [isModelLoaded, setIsModelLoaded] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isExporting, setIsExporting] = useState(false);
  const [showExportMenu, setShowExportMenu] = useState(false);

  // Refs to access Three.js objects inside interaction handlers
  const meshRefs = useRef<THREE.Mesh[]>([]);

  useEffect(() => {
    if (!isModelLoaded || !mountRef.current) return;

    // --- 1. Scene Setup ---
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0xf8fafc); // Slate-50 equivalent
    // Add subtle fog for depth
    scene.fog = new THREE.Fog(0xf8fafc, 5, 20);

    const camera = new THREE.PerspectiveCamera(45, mountRef.current.clientWidth / mountRef.current.clientHeight, 0.1, 100);
    camera.position.set(3, 4, 3); 
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(mountRef.current.clientWidth, mountRef.current.clientHeight);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    mountRef.current.appendChild(renderer.domElement);

    // --- Controls ---
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.enableZoom = true;
    controls.autoRotate = true;
    controls.autoRotateSpeed = 1.0;

    controls.addEventListener('start', () => {
      controls.autoRotate = false;
    });

    // --- 2. Lighting ---
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.7);
    scene.add(ambientLight);

    const dirLight = new THREE.DirectionalLight(0xffffff, 1);
    dirLight.position.set(5, 10, 7);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.width = 1024;
    dirLight.shadow.mapSize.height = 1024;
    scene.add(dirLight);

    const fillLight = new THREE.DirectionalLight(0xffffff, 0.5);
    fillLight.position.set(-5, 2, -5);
    scene.add(fillLight);

    // --- 3. Geometry (The Flip-Flop Sandal) ---
    const sandalGroup = new THREE.Group();

    // Main Material (Sole)
    const mainMaterial = new THREE.MeshPhysicalMaterial({
      color: selectedMat.color,
      roughness: selectedMat.roughness,
      metalness: selectedMat.metalness,
      transmission: selectedMat.transmission || 0,
      thickness: 1.0,
      clearcoat: 0.2,
    });

    // Strap Material (Rubber/Plastic usually, let's make it contrast or same)
    const strapMaterial = new THREE.MeshStandardMaterial({
        color: 0x333333,
        roughness: 0.4,
        metalness: 0.1
    });

    // --- 3a. The Sole ---
    const soleShape = new THREE.Shape();

    // Drawing a foot-like shape
    const length = 3.5;
    const widthHeel = 1.2;
    const widthToe = 1.6;

    soleShape.moveTo(0, -length/2); // Heel center
    // Right side curve
    soleShape.bezierCurveTo(widthHeel/1.5, -length/2, widthToe/1.2, length/2, 0.2, length/2);
    // Top (Toes)
    soleShape.bezierCurveTo(-0.2, length/2, -widthToe/1.2, length/2, -widthToe/1.2, length/4);
    // Left side curve (Arch)
    soleShape.bezierCurveTo(-widthToe/1.5, 0, -widthHeel/1.5, -length/2, 0, -length/2);

    const extrudeSettings = {
      steps: 2,
      depth: 0.25, // Sole thickness
      bevelEnabled: true,
      bevelThickness: 0.05,
      bevelSize: 0.05,
      bevelSegments: 4
    };

    const soleGeo = new THREE.ExtrudeGeometry(soleShape, extrudeSettings);
    const sole = new THREE.Mesh(soleGeo, mainMaterial);
    sole.rotation.x = -Math.PI / 2; // Lay flat
    sole.castShadow = true;
    sole.receiveShadow = true;
    sandalGroup.add(sole);

    // --- 3b. The Straps (Y-Shape) ---
    // We'll use TubeGeometry along a curve

    // Left Strap Path
    const leftStrapCurve = new THREE.CatmullRomCurve3([
        new THREE.Vector3(-0.6, 0.1, 0.5), // Side anchor
        new THREE.Vector3(-0.4, 0.6, 0.8), // Arch up
        new THREE.Vector3(0, 0.5, 1.4), // Toe post top
        new THREE.Vector3(0, 0.1, 1.4), // Toe post anchor
    ]);
    const leftStrapGeo = new THREE.TubeGeometry(leftStrapCurve, 20, 0.08, 8, false);
    const leftStrap = new THREE.Mesh(leftStrapGeo, strapMaterial);
    leftStrap.castShadow = true;
    sandalGroup.add(leftStrap);

    // Right Strap Path
    const rightStrapCurve = new THREE.CatmullRomCurve3([
        new THREE.Vector3(0.6, 0.1, 0.5), // Side anchor
        new THREE.Vector3(0.4, 0.6, 0.8), // Arch up
        new THREE.Vector3(0, 0.5, 1.4), // Toe post top
    ]);
    const rightStrapGeo = new THREE.TubeGeometry(rightStrapCurve, 20, 0.08, 8, false);
    const rightStrap = new THREE.Mesh(rightStrapGeo, strapMaterial);
    rightStrap.castShadow = true;
    sandalGroup.add(rightStrap);

    // Store references
    meshRefs.current = [sole]; // Only changing the sole material for now

    scene.add(sandalGroup);

    // Center the group
    new THREE.Box3().setFromObject(sandalGroup).getCenter(sandalGroup.position).multiplyScalar(-1);

    // --- 4. Animation ---
    let animationId: number;
    const animate = () => {
      animationId = requestAnimationFrame(animate);
      controls.update();

      // Floating animation
      const time = Date.now() * 0.001;
      sandalGroup.position.y = (Math.sin(time) * 0.05) - 0.1; // Offset slightly to account for centering

      renderer.render(scene, camera);
    };
    animate();

    // --- 5. Cleanup ---
    const handleResize = () => {
      if (!mountRef.current) return;
      camera.aspect = mountRef.current.clientWidth / mountRef.current.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(mountRef.current.clientWidth, mountRef.current.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(animationId);
      controls.dispose();
      if (mountRef.current) {
        mountRef.current.removeChild(renderer.domElement);
      }
      soleGeo.dispose();
      leftStrapGeo.dispose();
      rightStrapGeo.dispose();
      mainMaterial.dispose();
      strapMaterial.dispose();
    };
  }, [isModelLoaded]);

  // --- Update Material ---
  useEffect(() => {
    meshRefs.current.forEach(mesh => {
      if (mesh.material instanceof THREE.MeshPhysicalMaterial) {
        mesh.material.color.setHex(selectedMat.color);
