import React, { useState } from 'react';
import { ClipboardCheck, ArrowRight, ArrowLeft, CheckCircle2, Factory, Leaf, Recycle, BrainCircuit, FileDown, AlertTriangle, Info } from 'lucide-react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell } from 'recharts';

const STAGES = [
    { id: 0, title: '材料與資源使用', icon: Factory },
    { id: 1, title: '環境排放與足跡', icon: Leaf },
    { id: 2, title: '產品使用與報廢', icon: Recycle },
    { id: 3, title: 'AI 永續評分', icon: BrainCircuit },
];

const CircularityCheckup: React.FC = () => {
    const [currentStage, setCurrentStage] = useState(0);
    const [formData, setFormData] = useState<Record<string, any>>({});

    const handleNext = () => {
        if (currentStage < STAGES.length - 1) setCurrentStage(prev => prev + 1);
    };

    const handlePrev = () => {
        if (currentStage > 0) setCurrentStage(prev => prev - 1);
    };

    const updateField = (key: string, value: any) => {
        setFormData(prev => ({ ...prev, [key]: value }));
    };

    const renderStageContent = () => {
        switch (currentStage) {
            case 0: return <StageOne data={formData} update={updateField} />;
            case 1: return <StageTwo data={formData} update={updateField} />;
            case 2: return <StageThree data={formData} update={updateField} />;
            case 3: return <StageFour data={formData} />;
            default: return null;
        }
    };

    return (
        <div className="h-full flex flex-col bg-gray-50 overflow-hidden">
            {/* Header */}
            <div className="bg-white border-b border-gray-200 px-8 py-6 flex-shrink-0">
                <div className="flex items-center gap-3 mb-2">
                    <div className="p-2 bg-sml-teal-50 text-sml-teal-600 rounded-lg">
                        <ClipboardCheck size={24} />
                    </div>
                    <div>
                        <h2 className="text-2xl font-bold text-gray-800">產品循環度檢核</h2>
                        <p className="text-xs text-gray-500 font-mono mt-1">Product Circularity Check-up</p>
                    </div>
                </div>
                <p className="text-gray-600 text-sm max-w-4xl mt-3 leading-relaxed bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                    <Info size={16} className="inline mr-2 text-blue-500 translate-y-[-2px]"/>
                    產品循環度檢核是產品經理與設計師的永續設計自評工具，透過 16 項核心參數，協助您量化評估產品的循環表現。本工具旨在開發初期識別並優化產品的維修性、回收性和資源效率，確保設計符合高標準的循環經濟要求。
                </p>
            </div>

            {/* Stepper */}
            <div className="bg-white border-b border-gray-200 px-8 py-4">
                <div className="flex items-center justify-between max-w-4xl mx-auto">
                    {STAGES.map((stage, index) => {
                        const Icon = stage.icon;
                        const isActive = index === currentStage;
                        const isCompleted = index < currentStage;

                        return (
                            <div key={stage.id} className="flex flex-col items-center relative z-10">
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all duration-300 ${
                                    isActive ? 'border-sml-teal-500 bg-sml-teal-50 text-sml-teal-600' :
                                    isCompleted ? 'border-sml-teal-500 bg-sml-teal-500 text-white' :
                                    'border-gray-200 bg-white text-gray-300'
                                }`}>
                                    {isCompleted ? <CheckCircle2 size={20} /> : <Icon size={20} />}
                                </div>
                                <span className={`text-xs font-medium mt-2 ${isActive ? 'text-sml-teal-600' : 'text-gray-400'}`}>
                                    {stage.title}
                                </span>
                                {/* Progress Line */}
                                {index < STAGES.length - 1 && (
                                    <div className={`absolute top-5 left-1/2 w-[calc(100%+20px)] md:w-[calc(200%)] h-0.5 -z-10 ${
                                        index < currentStage ? 'bg-sml-teal-500' : 'bg-gray-200'
                                    }`} style={{ transform: 'translateX(50%)' }}></div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Content Body */}
            <div className="flex-1 overflow-y-auto p-8">
                <div className="max-w-4xl mx-auto bg-white rounded-2xl shadow-sm border border-gray-200 p-8 min-h-[500px]">
                    {renderStageContent()}
                </div>
            </div>

            {/* Footer Actions */}
            <div className="bg-white border-t border-gray-200 px-8 py-4 flex justify-between items-center flex-shrink-0">
                <button 
                    onClick={handlePrev} 
                    disabled={currentStage === 0}
                    className="flex items-center gap-2 px-6 py-2.5 rounded-xl text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed font-medium transition-colors"
                >
                    <ArrowLeft size={18} /> 上一步
                </button>

                {currentStage < STAGES.length - 1 ? (
                    <button 
                        onClick={handleNext} 
                        className="flex items-center gap-2 px-8 py-2.5 rounded-xl bg-sml-teal-600 text-white hover:bg-sml-teal-700 font-medium shadow-lg shadow-sml-teal-200 transition-all hover:translate-y-[-1px]"
                    >
                        下一步 <ArrowRight size={18} />
                    </button>
                ) : (
                    <button 
                        onClick={() => alert("檢核完成！")}
                        className="flex items-center gap-2 px-8 py-2.5 rounded-xl bg-sml-slate-800 text-white hover:bg-sml-slate-900 font-medium shadow-lg transition-all"
                    >
                        完成檢核
                    </button>
                )}
            </div>
        </div>
    );
};

