const RadioGroup: React.FC<{
    label: string;
    name: string;
    options: { value: string; label: string; hasInput?: boolean }[];
    selectedValue: string;
    inputValue?: string;
    onChange: (val: string, inputVal?: string) => void;
}> = ({ label, name, options, selectedValue, inputValue, onChange }) => (
    <div className="mb-8">
        <label className="block text-sm font-bold text-gray-800 mb-3">{label}</label>
        <div className="space-y-3">
            {options.map((opt) => (
                <label key={opt.value} className={`flex items-start p-3 rounded-lg border cursor-pointer transition-all ${
                    selectedValue === opt.value ? 'border-sml-teal-500 bg-sml-teal-50' : 'border-gray-200 hover:border-gray-300'
                }`}>
                    <input 
                        type="radio" 
                        name={name} 
                        value={opt.value}
                        checked={selectedValue === opt.value}
                        onChange={() => onChange(opt.value)}
                        className="mt-1 w-4 h-4 text-sml-teal-600 focus:ring-sml-teal-500"
                    />
                    <div className="ml-3 text-sm text-gray-700 w-full">
                        {opt.label.split('[__]').map((part, i, arr) => (
                            <React.Fragment key={i}>
                                {part}
                                {i < arr.length - 1 && (
                                    <input 
                                        type="text" 
                                        value={inputValue || ''}
                                        onChange={(e) => onChange(opt.value, e.target.value)}
                                        onClick={(e) => {
                                            e.stopPropagation(); // Prevent clicking input from triggering radio toggle logic unnecessarily
                                            onChange(opt.value, inputValue); // Ensure radio is selected
                                        }}
                                        disabled={selectedValue !== opt.value}
                                        className="mx-2 w-16 border-b border-gray-400 focus:border-sml-teal-500 outline-none bg-transparent text-center font-bold text-sml-teal-700"
                                    />
                                )}
                            </React.Fragment>
                        ))}
                    </div>
                </label>
            ))}
        </div>
    </div>
);

