interface ProjectRecordsProps {
    onSelectProject: (project: ProjectHistory) => void;
}

const ProjectRecords: React.FC<ProjectRecordsProps> = ({ onSelectProject }) => {
    const [projects, setProjects] = useState<ProjectHistory[]>(INITIAL_PROJECTS);
    const [selectedIds, setSelectedIds] = useState<Set<number>>(new Set());
    const [searchTerm, setSearchTerm] = useState('');

    const toggleSelection = (id: number, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSet = new Set(selectedIds);
        if (newSet.has(id)) {
            newSet.delete(id);
        } else {
            newSet.add(id);
        }
        setSelectedIds(newSet);
    };

    const handleDelete = () => {
        if (window.confirm(`確定要刪除選取的 ${selectedIds.size} 個專案紀錄嗎？`)) {
            setProjects(prev => prev.filter(p => !selectedIds.has(p.id)));
            setSelectedIds(new Set());
        }
    };

    const filteredProjects = projects.filter(p => 
        p.title.includes(searchTerm) || p.description.includes(searchTerm)
    );

    return (
        <div className="h-full bg-gray-50 flex flex-col">
            {/* Header */}
            <div className="bg-white border-b border-gray-200 px-8 py-6 flex-shrink-0">
                <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-sml-teal-50 text-sml-teal-600 rounded-lg">
                            <FolderClock size={24} />
                        </div>
                        <div>
                            <h2 className="text-2xl font-bold text-gray-800">專案紀錄</h2>
                            <p className="text-gray-500 text-sm">檢視或繼續您過去的模擬專案</p>
                        </div>
                    </div>

                    {selectedIds.size > 0 && (
                        <button 
                            onClick={handleDelete}
                            className="flex items-center gap-2 px-4 py-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition-colors text-sm font-medium animate-in fade-in zoom-in-95"
                        >
                            <Trash2 size={16} />
                            刪除 ({selectedIds.size})
                        </button>
                    )}
                </div>

                <div className="relative max-w-md">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text" 
                        placeholder="搜尋專案名稱或關鍵字..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 bg-gray-100 border-none rounded-xl focus:ring-2 focus:ring-sml-teal-200 focus:bg-white transition-all outline-none text-sm"
                    />
                </div>
            </div>

            {/* List */}
            <div className="flex-1 overflow-y-auto p-8">
                <div className="max-w-4xl mx-auto space-y-4">
                    {filteredProjects.map((project) => {
                        const isSelected = selectedIds.has(project.id);
                        return (
                            <div 
                                key={project.id} 
                                className={`group bg-white rounded-2xl border transition-all duration-200 overflow-hidden relative flex items-center ${
                                    isSelected 
                                    ? 'border-sml-teal-500 shadow-md bg-sml-teal-50/10' 
                                    : 'border-gray-200 shadow-sm hover:shadow-md hover:border-sml-teal-200'
                                }`}
                            >
                                {/* Checkbox Area */}
                                <div 
                                    className="pl-5 pr-2 py-6 cursor-pointer self-stretch flex items-center"
                                    onClick={(e) => toggleSelection(project.id, e)}
                                >
                                    <div className={`transition-colors ${isSelected ? 'text-sml-teal-600' : 'text-gray-300 group-hover:text-gray-400'}`}>
                                        {isSelected ? <CheckSquare size={20} /> : <Square size={20} />}
                                    </div>
                                </div>

                                {/* Content Area - Click to Navigate */}
                                <div 
                                    onClick={() => onSelectProject(project)}
                                    className="flex-1 p-5 pl-2 cursor-pointer"
                                >
                                    <div className="flex items-center gap-3 mb-1">
                                        <h3 className="font-bold text-gray-800 text-lg group-hover:text-sml-teal-700 transition-colors">
                                            {project.title}
                                        </h3>
                                        <span className="text-xs text-gray-400 flex items-center gap-1 bg-gray-100 px-2 py-0.5 rounded-full">
                                            <Calendar size={12} /> {project.date}
                                        </span>
                                    </div>
                                    <p className="text-gray-500 text-sm line-clamp-2">{project.description}</p>
                                </div>

                                {/* Action Arrow */}
                                <div className="pr-5 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button 
                                        onClick={() => onSelectProject(project)}
                                        className="p-2 bg-sml-teal-50 text-sml-teal-600 rounded-full hover:bg-sml-teal-100"
                                    >
                                        <ArrowRight size={18} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}

                    {filteredProjects.length === 0 && (
                        <div className="text-center py-12 text-gray-400 border-2 border-dashed border-gray-200 rounded-2xl">
                            <FolderClock size={48} className="mx-auto mb-4 opacity-20" />
                            <p>沒有找到符合的專案</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

