import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Navbar from './components/Navbar';
import Dashboard from './components/Dashboard';
import ChatPanel from './components/Chat/ChatPanel';
import MaterialDatabase from './components/MaterialDatabase';
import ReachDatabase from './components/ReachDatabase';
import MaterialSimulation from './components/Simulation/MaterialSimulation';
import ProjectRecords from './components/ProjectRecords';
import CircularityCheckup from './components/CircularityCheckup';
import ProjectChatView from './components/Chat/ProjectChatView';
import { ViewMode, ProjectHistory } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewMode>(ViewMode.DASHBOARD);
  const [selectedProject, setSelectedProject] = useState<ProjectHistory | null>(null);

  const handleProjectSelect = (project: ProjectHistory) => {
    setSelectedProject(project);
    setCurrentView(ViewMode.PROJECT_CHAT);
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewMode.DASHBOARD:
        return <Dashboard onNavigate={setCurrentView} />;
      case ViewMode.CHAT:
        return <ChatPanel />;
      case ViewMode.PROJECT_CHAT:
        if (selectedProject) {
            return (
                <ProjectChatView 
                    project={selectedProject} 
                    onBack={() => setCurrentView(ViewMode.PROJECT_RECORDS)} 
                />
            );
        }
        return <ProjectRecords onSelectProject={handleProjectSelect} />;
      case ViewMode.SIMULATION:
        return <MaterialSimulation />;
      case ViewMode.ISO_DB:
        return <div className="p-8 text-gray-500 text-center">ISO 資料庫模組 (即將推出)</div>;
      case ViewMode.MATERIAL_DB:
        return <MaterialDatabase />;
      case ViewMode.REACH_LIST:
        return <ReachDatabase />;
      case ViewMode.PROJECT_RECORDS:
        return <ProjectRecords onSelectProject={handleProjectSelect} />;
      case ViewMode.CIRCULARITY_CHECK:
        return <CircularityCheckup />;
      default:
        return <Dashboard onNavigate={setCurrentView} />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-white font-sans">
        {/* Left Panel: Sidebar (Fixed width, e.g., 280px ~ 1/4ish on desktop but fixed is better for UX) */}
        <aside className="w-72 flex-shrink-0 hidden md:block h-full z-20">
            <Sidebar currentView={currentView} onViewChange={setCurrentView} />
        </aside>

        {/* Right Area: Main Content */}
        <div className="flex-1 flex flex-col h-full min-w-0">
            {/* Navbar */}
            <Navbar />

            {/* Content Area */}
            <main className="flex-1 overflow-hidden relative">
                {renderContent()}
            </main>
        </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { MessageSquarePlus, FolderClock, BookOpen, Database, LayoutDashboard, Bookmark, ShieldAlert, ChevronDown, ChevronRight, Box, ClipboardCheck } from 'lucide-react';
import { ViewMode } from '../types';
import Logo from './Logo';

interface SidebarProps {
  currentView: ViewMode;
  onViewChange: (view: ViewMode) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, onViewChange }) => {
  // State to manage accordion expansion
  const [isMaterialDbOpen, setIsMaterialDbOpen] = useState(false);

  // Automatically open the accordion if a child view is active
  useEffect(() => {
    if (currentView === ViewMode.MATERIAL_DB || currentView === ViewMode.REACH_LIST) {
        setIsMaterialDbOpen(true);
    }
  }, [currentView]);

  const handleMaterialDbClick = () => {
      setIsMaterialDbOpen(!isMaterialDbOpen);
      // Optional: Navigate to the first child if opening and not currently on a child
      if (!isMaterialDbOpen && currentView !== ViewMode.MATERIAL_DB && currentView !== ViewMode.REACH_LIST) {
          onViewChange(ViewMode.MATERIAL_DB);
      }
  };

  const isMaterialSectionActive = currentView === ViewMode.MATERIAL_DB || currentView === ViewMode.REACH_LIST;

  return (
