        >
            <MessageSquarePlus size={18} className={currentView === ViewMode.CHAT ? 'text-sml-teal-600' : 'text-gray-400'} />
            新對話
        </button>

        <button
            onClick={() => onViewChange(ViewMode.SIMULATION)}
            className={`w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium rounded-lg transition-all duration-200 ${
                currentView === ViewMode.SIMULATION
                ? 'bg-sml-teal-50 text-sml-teal-700 shadow-sm' 
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
            }`}
        >
            <Box size={18} className={currentView === ViewMode.SIMULATION ? 'text-sml-teal-600' : 'text-gray-400'} />
            模擬示意
        </button>

         <button
            onClick={() => onViewChange(ViewMode.CIRCULARITY_CHECK)}
            className={`w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium rounded-lg transition-all duration-200 ${
                currentView === ViewMode.CIRCULARITY_CHECK
                ? 'bg-sml-teal-50 text-sml-teal-700 shadow-sm' 
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
            }`}
        >
            <ClipboardCheck size={18} className={currentView === ViewMode.CIRCULARITY_CHECK ? 'text-sml-teal-600' : 'text-gray-400'} />
            產品循環度檢核
        </button>

        <button
            onClick={() => onViewChange(ViewMode.PROJECT_RECORDS)}
            className={`w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium rounded-lg transition-all duration-200 ${
                currentView === ViewMode.PROJECT_RECORDS
                ? 'bg-sml-teal-50 text-sml-teal-700 shadow-sm' 
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
