3D 預覽區：嵌入下方的格式內容

<!DOCTYPE html>
<html lang="zh-TW">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>SML AI Agent - 3D 模型預覽</title>

    <script type="module" src="https://ajax.googleapis.com/ajax/libs/model-viewer/3.4.0/model-viewer.min.js"></script>

    <style>
        /* 頁面基本設定 */
        body {
            margin: 0;
            padding: 0;
            font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
            background-color: #f5f5f5; /* 淺灰背景，突顯產品 */
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
        }

        /* 2. Model Viewer 本體的樣式 */
        model-viewer {
            width: 100%;
            height: 100%;
            background-color: #ffffff; /* 模型背景色 */
            --poster-color: #ffffff;
        }

        /* 3. 自定義讀取條 (Progress Bar) 的樣式 */
        .progress-bar {
            display: block;
            width: 33%;
            height: 10%;
            max-height: 2%;
            position: absolute;
            left: 50%;
            top: 50%;
            transform: translate3d(-50%, -50%, 0);
            border-radius: 25px;
            box-shadow: 0px 3px 10px 3px rgba(0, 0, 0, 0.5), 0px 0px 5px 1px rgba(0, 0, 0, 0.6);
            border: 1px solid rgba(255, 255, 255, 0.9);
            background-color: rgba(0, 0, 0, 0.5);
        }

        .progress-bar.hide {
            visibility: hidden;
            transition: visibility 0.3s;
        }

        .update-bar {
            background-color: #fff;
            width: 0%;
            height: 100%;
            border-radius: 25px;
            float: left;
            transition: width 0.3s;
        }

        /* 4. AR 按鈕樣式 */
        #ar-button {
            background-image: url(https://modelviewer.dev/shared-assets/icons/ic_view_in_ar_new_googblue_48dp.png);
            background-repeat: no-repeat;
            background-size: 20px 20px;
            background-position: 12px 50%;
            background-color: #fff;
            position: absolute;
            left: 50%;
            transform: translateX(-50%);
            white-space: nowrap;
            bottom: 16px; /* 距離底部的位置 */
            padding: 0px 16px 0px 40px;
            font-family: Roboto, Regular, Helvetica Neue, sans-serif;
            font-size: 14px;
            color:#4285f4;
            height: 36px;
            line-height: 36px;
            border-radius: 18px;
            border: 1px solid #DADCE0;
        }

        #ar-button:active {
            background-color: #E8EAED;
        }

        #ar-button:focus {
            outline: none;
        }

        #ar-button:focus-visible {
            outline: 1px solid #4285f4;
        }

        /* AR 提示手勢圖示 */
        #ar-prompt {
            position: absolute;
            left: 50%;
            bottom: 60px;
            animation: notify-arrow 3s infinite;
            display: none; /* 預設隱藏，AR 模式下才會自動出現 */
        }

        @keyframes notify-arrow {
            0% { transform: translateX(-50%) translateY(0); opacity: 1; }
            100% { transform: translateX(-50%) translateY(-10px); opacity: 0; }
        }
    </style>
</head>
<body>

    <model-viewer 
        src="Copilot3D-beed940e-4d0d-44bc-92f7-a2ec46573c84.glb" 
        ar 
        ar-modes="webxr scene-viewer quick-look" 
        camera-controls 
        tone-mapping="neutral" 
        poster="poster.webp" 
        shadow-intensity="0.97" 
        shadow-softness="0.87">

        <div class="progress-bar hide" slot="progress-bar">
            <div class="update-bar"></div>
        </div>

        <button slot="ar-button" id="ar-button">
            View in your space
        </button>

        <div id="ar-prompt">
            <img src="https://modelviewer.dev/shared-assets/icons/hand.png">
        </div>

    </model-viewer>

    <script>
        const modelViewer = document.querySelector('model-viewer');
        const onProgress = (event) => {
          const progressBar = event.target.querySelector('.progress-bar');
          const updatingBar = event.target.querySelector('.update-bar');
          updatingBar.style.width = `${event.detail.totalProgress * 100}%`;
          if (event.detail.totalProgress === 1) {
            progressBar.classList.add('hide');
            event.target.removeEventListener('progress', onProgress);
          } else {
            progressBar.classList.remove('hide');
          }
        };
        document.querySelector('model-viewer').addEventListener('progress', onProgress);
    </script>

</body>
</html>

