// Initial Mock Data
const INITIAL_RADAR = [
  { subject: '抗拉強度', A: 120, fullMark: 150 },
  { subject: '衝擊', A: 98, fullMark: 150 },
  { subject: '耐熱', A: 86, fullMark: 150 },
  { subject: '化學', A: 99, fullMark: 150 },
  { subject: '紫外線', A: 85, fullMark: 150 },
  { subject: '彎曲', A: 65, fullMark: 150 },
];

const INITIAL_LIFECYCLE = [
  { name: '生產', val: 30 },
  { name: '運輸', val: 15 },
  { name: '使用', val: 10 },
  { name: '廢棄', val: 45 },
];

const AnalysisPanel: React.FC = () => {
  const [imagePrompt, setImagePrompt] = useState('');
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  // Dynamic Analysis State
  const [analysisData, setAnalysisData] = useState({
      radar: INITIAL_RADAR,
      lifecycle: INITIAL_LIFECYCLE,
      recyclingRate: 98,
      cost: 350 // NTD
  });

  // Helper to generate random number in range
  const getRandom = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

  const handleGenerate = async () => {
    if (!imagePrompt.trim()) return;

    setIsGenerating(true);

    // Simulate updating analysis data based on the prompt (Mock AI Analysis)
    // In a real app, this data would come from the LLM response
    const newRadar = INITIAL_RADAR.map(item => ({
        ...item,
        A: getRandom(50, 145) // Randomize strength/durability stats
    }));

    const newLifecycle = [
        { name: '生產', val: getRandom(20, 60) },
        { name: '運輸', val: getRandom(5, 25) },
        { name: '使用', val: getRandom(5, 30) },
        { name: '廢棄', val: getRandom(10, 50) },
    ];

    try {
      // 1. Generate Image
      const result = await generateMaterialImage(imagePrompt);
      if (result) {
        setGeneratedImage(result);
      } else {
        console.warn("No image returned");
      }

      // 2. Update Charts & Stats (Synced with generation)
      setAnalysisData({
          radar: newRadar,
          lifecycle: newLifecycle,
          recyclingRate: getRandom(60, 99),
          cost: getRandom(120, 1200) // Random price between NT$120 - NT$1200
      });

    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleGenerate();
    }
  };

  return (
    <div className="h-full overflow-y-auto bg-white border-l border-gray-200 flex flex-col">
      <div className="p-4 border-b border-gray-100 flex items-center justify-between">
