                        </div>
                    )
                )}

                {isGenerating && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center text-sml-teal-600 bg-white/50 backdrop-blur-sm z-10">
                        <Loader2 size={32} className="animate-spin mb-2" />
