                        className="flex-1 bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-sml-teal-100 focus:border-sml-teal-400 transition-all placeholder-gray-400"
                    />
                    <button 
                        onClick={handleGenerate}
                        disabled={isGenerating || !imagePrompt.trim()}
                        className="bg-sml-teal-500 hover:bg-sml-teal-600 text-white p-2 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex-shrink-0"
                        title="生成圖片"
                    >
                        {isGenerating ? <Loader2 size={18} className="animate-spin"/> : <Wand2 size={18} />}
