    const newLifecycle = [
        { name: '生產', val: getRandom(20, 60) },
        { name: '運輸', val: getRandom(5, 25) },
        { name: '使用', val: getRandom(5, 30) },
        { name: '廢棄', val: getRandom(10, 50) },
